import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { registerConfigHandler } from '../../../src/extension/config/listener';

function makeProvider() {
  return {
    refreshPhysicsSettings: vi.fn(),
    refreshToggleSettings: vi.fn(),
    refreshSettings: vi.fn(),
    refreshGroupSettings: vi.fn(),
    refresh: vi.fn().mockResolvedValue(undefined),
    emitEvent: vi.fn(),
    invalidateTimelineCache: vi.fn().mockResolvedValue(undefined),
    sendPlaybackSpeed: vi.fn(),
  };
}

function makeContext() {
  return {
    subscriptions: [] as { dispose: () => void }[],
  };
}

function getConfigListener() {
  const mock = vscode.workspace.onDidChangeConfiguration as unknown as {
    mock: { calls: unknown[][] };
  };
  return mock.mock.calls[0]?.[0] as (event: { affectsConfiguration: (key: string) => boolean }) => void;
}

describe('configListener', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('calls refreshPhysicsSettings for physics configuration changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.physics' });

    expect(provider.refreshPhysicsSettings).toHaveBeenCalledOnce();
  });

  it('calls refreshToggleSettings for disabledPlugins changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.disabledPlugins' });

    expect(provider.refreshToggleSettings).toHaveBeenCalledOnce();
  });

  it('calls refreshSettings for display-only setting changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.showLabels' });

    expect(provider.refreshSettings).toHaveBeenCalledOnce();
  });

  it('rebuilds display state instead of refreshing the graph when show-orphans changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.showOrphans' });

    expect(provider.refreshSettings).toHaveBeenCalledOnce();
    expect(provider.refresh).not.toHaveBeenCalled();
  });

  it('calls refreshSettings for node and edge control changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.nodeColors' });
    listener({ affectsConfiguration: (key) => key === 'codegraphy.edgeVisibility' });

    expect(provider.refreshSettings).toHaveBeenCalledTimes(2);
    expect(provider.refresh).not.toHaveBeenCalled();
  });

  it('triggers a full refresh for plugin order changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.pluginOrder' || key === 'codegraphy' });

    expect(provider.refresh).toHaveBeenCalledOnce();
  });

  it('skips re-analysis for legend configuration changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.legend' });

    expect(provider.refresh).not.toHaveBeenCalled();
    expect(provider.refreshSettings).not.toHaveBeenCalled();
  });

  it('debounces legend configuration syncs and refreshes group settings once', () => {
    vi.useFakeTimers();
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy.legend' });
    listener({ affectsConfiguration: (key) => key === 'codegraphy.hiddenPluginGroups' });

    expect(provider.refreshGroupSettings).not.toHaveBeenCalled();

    vi.advanceTimersByTime(299);
    expect(provider.refreshGroupSettings).not.toHaveBeenCalled();

    vi.advanceTimersByTime(1);
    expect(provider.refreshGroupSettings).toHaveBeenCalledOnce();

    vi.useRealTimers();
  });

  it('triggers full refresh for unrecognized codegraphy settings', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({ affectsConfiguration: (key) => key === 'codegraphy' || key === 'codegraphy.maxFiles' });

    expect(provider.refresh).toHaveBeenCalledOnce();
    expect(provider.emitEvent).toHaveBeenCalledWith('workspace:configChanged', {
      key: 'codegraphy',
      value: undefined,
      old: undefined,
    });
  });

  it('invalidates timeline cache when filterPatterns change', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({
      affectsConfiguration: (key) =>
        key === 'codegraphy' ||
        key === 'codegraphy.filterPatterns',
    });

    expect(provider.invalidateTimelineCache).toHaveBeenCalledOnce();
  });

  it('sends playback speed when timeline.playbackSpeed changes', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    const listener = getConfigListener();
    listener({
      affectsConfiguration: (key) =>
        key === 'codegraphy' ||
        key === 'codegraphy.timeline.playbackSpeed',
    });

    expect(provider.sendPlaybackSpeed).toHaveBeenCalledOnce();
  });

  it('adds a subscription to the context', () => {
    const context = makeContext();
    const provider = makeProvider();

    registerConfigHandler(context as unknown as vscode.ExtensionContext, provider as never);

    expect(context.subscriptions.length).toBe(1);
  });
});

import { describe, it, expect } from 'vitest';
import { classifyConfigChange } from '../../../src/extension/config/classify';

function makeEvent(...matchingKeys: string[]) {
  const keySet = new Set(matchingKeys);
  return {
    affectsConfiguration: (key: string) => keySet.has(key),
  };
}

describe('classifyConfigChange', () => {
  describe('physics category', () => {
    it('returns physics when codegraphy.physics is affected', () => {
      const event = makeEvent('codegraphy.physics');
      expect(classifyConfigChange(event)).toBe('physics');
    });

    it('returns physics even when other keys are also affected', () => {
      const event = makeEvent('codegraphy.physics', 'codegraphy.showLabels', 'codegraphy');
      expect(classifyConfigChange(event)).toBe('physics');
    });
  });

  describe('toggles category', () => {
    it('returns toggles when codegraphy.disabledPlugins is affected', () => {
      const event = makeEvent('codegraphy.disabledPlugins');
      expect(classifyConfigChange(event)).toBe('toggles');
    });

    it('returns toggles when disabled plugins are affected alongside other keys', () => {
      const event = makeEvent('codegraphy.disabledPlugins', 'codegraphy.showLabels');
      expect(classifyConfigChange(event)).toBe('toggles');
    });
  });

  describe('display category', () => {
    it('returns display when codegraphy.showOrphans is affected', () => {
      const event = makeEvent('codegraphy.showOrphans');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.directionMode is affected', () => {
      const event = makeEvent('codegraphy.directionMode');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.directionColor is affected', () => {
      const event = makeEvent('codegraphy.directionColor');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.particleSpeed is affected', () => {
      const event = makeEvent('codegraphy.particleSpeed');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.particleSize is affected', () => {
      const event = makeEvent('codegraphy.particleSize');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.showLabels is affected', () => {
      const event = makeEvent('codegraphy.showLabels');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('returns display when codegraphy.bidirectionalEdges is affected', () => {
      const event = makeEvent('codegraphy.bidirectionalEdges');
      expect(classifyConfigChange(event)).toBe('display');
    });
  });

  describe('legend category', () => {
    it('returns legend when codegraphy.legend is affected', () => {
      const event = makeEvent('codegraphy.legend');
      expect(classifyConfigChange(event)).toBe('legend');
    });

  });

  describe('general category', () => {
    it('returns general when only codegraphy root is affected', () => {
      const event = makeEvent('codegraphy');
      expect(classifyConfigChange(event)).toBe('general');
    });

    it('returns general when codegraphy is affected but no specific sub-key matches', () => {
      const event = makeEvent('codegraphy', 'codegraphy.maxFiles');
      expect(classifyConfigChange(event)).toBe('general');
    });
  });

  describe('null return', () => {
    it('returns null when no codegraphy configuration is affected', () => {
      const event = makeEvent('editor.fontSize');
      expect(classifyConfigChange(event)).toBeNull();
    });

    it('returns null when affectsConfiguration always returns false', () => {
      const event = { affectsConfiguration: () => false };
      expect(classifyConfigChange(event)).toBeNull();
    });
  });

  describe('priority ordering', () => {
    it('physics takes priority over toggles', () => {
      const event = makeEvent('codegraphy.physics', 'codegraphy.disabledPlugins');
      expect(classifyConfigChange(event)).toBe('physics');
    });

    it('toggles takes priority over display', () => {
      const event = makeEvent('codegraphy.disabledPlugins', 'codegraphy.showLabels');
      expect(classifyConfigChange(event)).toBe('toggles');
    });

    it('display takes priority over legend', () => {
      const event = makeEvent('codegraphy.showLabels', 'codegraphy.legend');
      expect(classifyConfigChange(event)).toBe('display');
    });

    it('legend takes priority over general', () => {
      const event = makeEvent('codegraphy.legend', 'codegraphy');
      expect(classifyConfigChange(event)).toBe('legend');
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { executeConfigAction } from '../../../src/extension/config/actions';

function makeProvider() {
  return {
    refreshPhysicsSettings: vi.fn(),
    refreshToggleSettings: vi.fn(),
    refreshSettings: vi.fn(),
    refreshGroupSettings: vi.fn(),
    refresh: vi.fn().mockResolvedValue(undefined),
    emitEvent: vi.fn(),
    invalidateTimelineCache: vi.fn().mockResolvedValue(undefined),
    sendPlaybackSpeed: vi.fn(),
  };
}

function makeEvent(...matchingKeys: string[]) {
  const keySet = new Set(matchingKeys);
  return {
    affectsConfiguration: (key: string) => keySet.has(key),
  };
}

describe('executeConfigAction', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('calls refreshPhysicsSettings for physics category', () => {
    const provider = makeProvider();
    const event = makeEvent();

    executeConfigAction('physics', event as never, provider as never);

    expect(provider.refreshPhysicsSettings).toHaveBeenCalledOnce();
    expect(provider.refresh).not.toHaveBeenCalled();
  });

  it('calls refreshToggleSettings for toggles category', () => {
    const provider = makeProvider();
    const event = makeEvent();

    executeConfigAction('toggles', event as never, provider as never);

    expect(provider.refreshToggleSettings).toHaveBeenCalledOnce();
    expect(provider.refresh).not.toHaveBeenCalled();
  });

  it('calls refreshSettings for display category', () => {
    const provider = makeProvider();
    const event = makeEvent();

    executeConfigAction('display', event as never, provider as never);

    expect(provider.refreshSettings).toHaveBeenCalledOnce();
    expect(provider.refresh).not.toHaveBeenCalled();
  });

  it('debounces legend settings syncs and refreshes group settings once', () => {
    vi.useFakeTimers();
    const provider = makeProvider();
    const event = makeEvent();

    executeConfigAction('legend', event as never, provider as never);
    executeConfigAction('legend', event as never, provider as never);

    expect(provider.refreshPhysicsSettings).not.toHaveBeenCalled();
    expect(provider.refreshToggleSettings).not.toHaveBeenCalled();
    expect(provider.refreshSettings).not.toHaveBeenCalled();
    expect(provider.refreshGroupSettings).not.toHaveBeenCalled();
    expect(provider.refresh).not.toHaveBeenCalled();

    vi.advanceTimersByTime(299);
    expect(provider.refreshGroupSettings).not.toHaveBeenCalled();

    vi.advanceTimersByTime(1);
    expect(provider.refreshGroupSettings).toHaveBeenCalledOnce();

    vi.useRealTimers();
  });

  describe('general category', () => {
    it('syncs the full settings snapshot before refreshing for general category changes', () => {
      const provider = makeProvider();
      const event = makeEvent('codegraphy.maxFiles');

      executeConfigAction('general', event as never, provider as never);

      expect(provider.refreshGroupSettings).toHaveBeenCalledOnce();
      expect(provider.refresh).toHaveBeenCalledOnce();
      expect(provider.refreshGroupSettings.mock.invocationCallOrder[0]).toBeLessThan(
        provider.refresh.mock.invocationCallOrder[0],
      );
    });

    it('calls refresh and emitEvent for general category', () => {
      const provider = makeProvider();
      const event = makeEvent();

      executeConfigAction('general', event as never, provider as never);

      expect(provider.refresh).toHaveBeenCalledOnce();
      expect(provider.emitEvent).toHaveBeenCalledWith('workspace:configChanged', {
        key: 'codegraphy',
        value: undefined,
        old: undefined,
      });
    });

    it('invalidates timeline cache when filterPatterns changes', () => {
      const provider = makeProvider();
      const event = makeEvent('codegraphy.filterPatterns');

      executeConfigAction('general', event as never, provider as never);

      expect(provider.invalidateTimelineCache).toHaveBeenCalledOnce();
    });

    it('invalidates timeline cache when timeline.maxCommits changes', () => {
      const provider = makeProvider();
      const event = makeEvent('codegraphy.timeline.maxCommits');

      executeConfigAction('general', event as never, provider as never);

      expect(provider.invalidateTimelineCache).toHaveBeenCalledOnce();
    });

    it('does not invalidate timeline cache when unrelated config changes', () => {
      const provider = makeProvider();
      const event = makeEvent();

      executeConfigAction('general', event as never, provider as never);

      expect(provider.invalidateTimelineCache).not.toHaveBeenCalled();
    });

    it('sends playback speed when timeline.playbackSpeed changes', () => {
      const provider = makeProvider();
      const event = makeEvent('codegraphy.timeline.playbackSpeed');

      executeConfigAction('general', event as never, provider as never);

      expect(provider.sendPlaybackSpeed).toHaveBeenCalledOnce();
    });

    it('does not send playback speed when unrelated config changes', () => {
      const provider = makeProvider();
      const event = makeEvent();

      executeConfigAction('general', event as never, provider as never);

      expect(provider.sendPlaybackSpeed).not.toHaveBeenCalled();
    });

    it('handles both filterPatterns and playbackSpeed changing at once', () => {
      const provider = makeProvider();
      const event = makeEvent('codegraphy.filterPatterns', 'codegraphy.timeline.playbackSpeed');

      executeConfigAction('general', event as never, provider as never);

      expect(provider.invalidateTimelineCache).toHaveBeenCalledOnce();
      expect(provider.sendPlaybackSpeed).toHaveBeenCalledOnce();
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { Configuration } from '../../../src/extension/config/reader';
import {
  DEFAULT_EXCLUDE_PATTERNS,
  type ICodeGraphyConfig,
} from '../../../src/extension/config/defaults';

// Mock vscode module
vi.mock('vscode', () => ({
  workspace: {
    getConfiguration: vi.fn(),
    onDidChangeConfiguration: vi.fn(() => ({ dispose: vi.fn() })),
  },
}));

import * as vscode from 'vscode';

describe('Configuration', () => {
  let mockConfig: Record<string, unknown>;

  beforeEach(() => {
    // Reset mock config to defaults
    mockConfig = {
      maxFiles: 500,
      include: ['**/*'],
      respectGitignore: true,
      showOrphans: true,
      plugins: [],
      disabledPlugins: [],
    };

    // Setup mock to return values from mockConfig
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: <T>(key: string, defaultValue: T): T => {
        return (mockConfig[key] as T) ?? defaultValue;
      },
    } as vscode.WorkspaceConfiguration);
  });

  describe('default values', () => {
    it('should return default maxFiles of 500', () => {
      const config = new Configuration();
      expect(config.maxFiles).toBe(500);
    });

    it('should return default include pattern', () => {
      const config = new Configuration();
      expect(config.include).toEqual(['**/*']);
    });

    it('should return default respectGitignore as true', () => {
      const config = new Configuration();
      expect(config.respectGitignore).toBe(true);
    });

    it('should return default showOrphans as true', () => {
      const config = new Configuration();
      expect(config.showOrphans).toBe(true);
    });

    it('should return default plugins as empty array', () => {
      const config = new Configuration();
      expect(config.plugins).toEqual([]);
    });

    it('should return default disabledPlugins as empty array', () => {
      const config = new Configuration();
      expect(config.disabledPlugins).toEqual([]);
    });
  });

  describe('custom values', () => {
    it('should return custom maxFiles', () => {
      mockConfig.maxFiles = 500;
      const config = new Configuration();
      expect(config.maxFiles).toBe(500);
    });

    it('should return custom include patterns', () => {
      mockConfig.include = ['src/**/*', 'lib/**/*'];
      const config = new Configuration();
      expect(config.include).toEqual(['src/**/*', 'lib/**/*']);
    });

    it('should return custom respectGitignore', () => {
      mockConfig.respectGitignore = false;
      const config = new Configuration();
      expect(config.respectGitignore).toBe(false);
    });

    it('should return custom showOrphans', () => {
      mockConfig.showOrphans = false;
      const config = new Configuration();
      expect(config.showOrphans).toBe(false);
    });

    it('should return custom plugins', () => {
      mockConfig.plugins = ['codegraphy-rust', 'codegraphy-go'];
      const config = new Configuration();
      expect(config.plugins).toEqual(['codegraphy-rust', 'codegraphy-go']);
    });

    it('should return custom disabledPlugins', () => {
      mockConfig.disabledPlugins = ['codegraphy.python'];
      const config = new Configuration();
      expect(config.disabledPlugins).toEqual(['codegraphy.python']);
    });
  });

  describe('getAll', () => {
    it('should return all configuration values', () => {
      const config = new Configuration();
      const all: ICodeGraphyConfig = config.getAll();

      expect(all).toEqual({
        maxFiles: 500,
        include: ['**/*'],
        respectGitignore: true,
        showOrphans: true,
        bidirectionalEdges: 'separate',
        plugins: [],
        disabledPlugins: [],
        pluginOrder: [],
      });
    });

    it('should return custom values in getAll', () => {
      mockConfig.maxFiles = 200;
      mockConfig.showOrphans = false;
      mockConfig.plugins = ['codegraphy-rust'];
      mockConfig.disabledPlugins = ['codegraphy.python'];

      const config = new Configuration();
      const all = config.getAll();

      expect(all.maxFiles).toBe(200);
      expect(all.showOrphans).toBe(false);
      expect(all.plugins).toEqual(['codegraphy-rust']);
      expect(all.disabledPlugins).toEqual(['codegraphy.python']);
    });
  });

  describe('onDidChange', () => {
    it('should register configuration change listener', () => {
      const config = new Configuration();
      const callback = vi.fn();

      config.onDidChange(callback);

      expect(vscode.workspace.onDidChangeConfiguration).toHaveBeenCalled();
    });

    it('should return a disposable', () => {
      const config = new Configuration();
      const disposable = config.onDidChange(() => {});

      expect(disposable).toHaveProperty('dispose');
    });
  });

  describe('timeline settings', () => {
    it('should return default timelineMaxCommits of 500', () => {
      mockConfig['timeline.maxCommits'] = 500;
      const config = new Configuration();
      expect(config.timelineMaxCommits).toBe(500);
    });

    it('should return custom timelineMaxCommits', () => {
      mockConfig['timeline.maxCommits'] = 1000;
      const config = new Configuration();
      expect(config.timelineMaxCommits).toBe(1000);
    });

    it('should return default timelinePlaybackSpeed of 1.0', () => {
      mockConfig['timeline.playbackSpeed'] = 1.0;
      const config = new Configuration();
      expect(config.timelinePlaybackSpeed).toBe(1.0);
    });

    it('should return custom timelinePlaybackSpeed', () => {
      mockConfig['timeline.playbackSpeed'] = 2.5;
      const config = new Configuration();
      expect(config.timelinePlaybackSpeed).toBe(2.5);
    });
  });

  describe('DEFAULT_EXCLUDE_PATTERNS', () => {
    it('should include node_modules', () => {
      expect(DEFAULT_EXCLUDE_PATTERNS).toContain('**/node_modules/**');
    });

    it('should include dist', () => {
      expect(DEFAULT_EXCLUDE_PATTERNS).toContain('**/dist/**');
    });

    it('should include .git', () => {
      expect(DEFAULT_EXCLUDE_PATTERNS).toContain('**/.git/**');
    });

    it('should include minified files', () => {
      expect(DEFAULT_EXCLUDE_PATTERNS).toContain('**/*.min.js');
    });

    it('should include source maps', () => {
      expect(DEFAULT_EXCLUDE_PATTERNS).toContain('**/*.map');
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { Configuration } from '../../../src/extension/config/reader';

describe('Configuration (configReaders)', () => {
  let mockConfig: Record<string, unknown>;
  let mockGet: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
    mockConfig = {};
    mockGet = vi.fn(<T>(key: string, defaultValue: T): T => {
      return (key in mockConfig ? mockConfig[key] : defaultValue) as T;
    });
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: mockGet,
    } as unknown as vscode.WorkspaceConfiguration);
  });

  describe('maxFiles', () => {
    it('returns the configured value', () => {
      mockConfig['maxFiles'] = 1000;
      expect(new Configuration().maxFiles).toBe(1000);
    });

    it('returns the default 500 when not configured', () => {
      expect(new Configuration().maxFiles).toBe(500);
    });

    it('reads from the codegraphy section', () => {
      void new Configuration().maxFiles;
      expect(vscode.workspace.getConfiguration).toHaveBeenCalledWith('codegraphy');
    });
  });

  describe('include', () => {
    it('returns the configured include patterns', () => {
      mockConfig['include'] = ['src/**/*'];
      expect(new Configuration().include).toEqual(['src/**/*']);
    });

    it('defaults to all files pattern', () => {
      expect(new Configuration().include).toEqual(['**/*']);
    });
  });

  describe('respectGitignore', () => {
    it('returns the configured value', () => {
      mockConfig['respectGitignore'] = false;
      expect(new Configuration().respectGitignore).toBe(false);
    });

    it('defaults to true', () => {
      expect(new Configuration().respectGitignore).toBe(true);
    });
  });

  describe('showOrphans', () => {
    it('returns the configured value', () => {
      mockConfig['showOrphans'] = false;
      expect(new Configuration().showOrphans).toBe(false);
    });

    it('defaults to true', () => {
      expect(new Configuration().showOrphans).toBe(true);
    });
  });

  describe('bidirectionalEdges', () => {
    it('returns the configured value', () => {
      mockConfig['bidirectionalEdges'] = 'combined';
      expect(new Configuration().bidirectionalEdges).toBe('combined');
    });

    it('defaults to separate', () => {
      expect(new Configuration().bidirectionalEdges).toBe('separate');
    });
  });

  describe('plugins', () => {
    it('returns the configured plugin list', () => {
      mockConfig['plugins'] = ['my-plugin'];
      expect(new Configuration().plugins).toEqual(['my-plugin']);
