    const config = { update: vi.fn().mockResolvedValue(undefined) };
    vi.mocked(getCodeGraphyConfiguration).mockReturnValue(config as never);
    const persistence = createSettingsConfigPersistence({
      dagModeKey: 'dagMode',
      nodeSizeModeKey: 'nodeSizeMode',
    });

